import{_ as o,o as s,c as i,ae as c}from"./chunks/framework.C7FLYIpo.js";const u=JSON.parse('{"title":"세션 관리 심층 분석","description":"심층 분석: 세션 저장소 + 트랜스크립트, 라이프사이클, (자동)컴팩션 내부 구조","frontmatter":{"title":"세션 관리 심층 분석","description":"심층 분석: 세션 저장소 + 트랜스크립트, 라이프사이클, (자동)컴팩션 내부 구조"},"headers":[],"relativePath":"reference/session-management-compaction.md","filePath":"reference/session-management-compaction.md","lastUpdated":null}'),l={name:"reference/session-management-compaction.md"};function a(n,e,d,t,r,p){return s(),i("div",null,[...e[0]||(e[0]=[c('<h1 id="세션-관리-및-컴팩션-심층-분석" tabindex="-1">세션 관리 및 컴팩션 (심층 분석) <a class="header-anchor" href="#세션-관리-및-컴팩션-심층-분석" aria-label="Permalink to &quot;세션 관리 및 컴팩션 (심층 분석)&quot;">​</a></h1><p>이 문서는 OpenClaw가 세션을 종단 간으로 관리하는 방법을 설명합니다:</p><ul><li><strong>세션 라우팅</strong> (인바운드 메시지가 <code>sessionKey</code>에 매핑되는 방식)</li><li><strong>세션 저장소</strong> (<code>sessions.json</code>) 및 추적 내용</li><li><strong>트랜스크립트 지속성</strong> (<code>*.jsonl</code>) 및 구조</li><li><strong>트랜스크립트 위생</strong> (실행 전 프로바이더별 수정)</li><li><strong>컨텍스트 제한</strong> (컨텍스트 창 대 추적 토큰)</li><li><strong>컴팩션</strong> (수동 + 자동 컴팩션) 및 사전 컴팩션 작업을 위한 훅 위치</li><li><strong>사일런트 하우스키핑</strong> (예: 사용자에게 표시되지 않아야 하는 메모리 쓰기)</li></ul><p>높은 수준의 개요를 먼저 원하는 경우 다음을 참조하십시오:</p><ul><li><a href="/openclaw-docs-ko/concepts/session">/concepts/session</a></li><li><a href="/openclaw-docs-ko/concepts/compaction">/concepts/compaction</a></li><li><a href="/openclaw-docs-ko/concepts/memory">/concepts/memory</a></li><li><a href="/openclaw-docs-ko/concepts/memory-search">/concepts/memory-search</a></li><li><a href="/openclaw-docs-ko/concepts/session-pruning">/concepts/session-pruning</a></li><li><a href="/openclaw-docs-ko/reference/transcript-hygiene">/reference/transcript-hygiene</a></li></ul><hr><h2 id="신뢰의-원천-게이트웨이" tabindex="-1">신뢰의 원천: 게이트웨이 <a class="header-anchor" href="#신뢰의-원천-게이트웨이" aria-label="Permalink to &quot;신뢰의 원천: 게이트웨이&quot;">​</a></h2><p>OpenClaw는 세션 상태를 소유하는 단일 <strong>게이트웨이 프로세스</strong>를 중심으로 설계됩니다.</p><ul><li>UI (macOS 앱, 웹 Control UI, TUI)는 세션 목록 및 토큰 수를 위해 게이트웨이를 쿼리해야 합니다.</li><li>원격 모드에서 세션 파일은 원격 호스트에 있습니다. &quot;로컬 Mac 파일 확인&quot;은 게이트웨이가 사용하는 내용을 반영하지 않습니다.</li></ul><hr><h2 id="두-가지-지속성-레이어" tabindex="-1">두 가지 지속성 레이어 <a class="header-anchor" href="#두-가지-지속성-레이어" aria-label="Permalink to &quot;두 가지 지속성 레이어&quot;">​</a></h2><p>OpenClaw는 두 레이어에 세션을 지속합니다:</p><ol><li><p><strong>세션 저장소 (<code>sessions.json</code>)</strong></p><ul><li>키/값 맵: <code>sessionKey -&gt; SessionEntry</code></li><li>소형, 가변형, 편집 (또는 항목 삭제)이 안전합니다</li><li>세션 메타데이터 (현재 세션 ID, 마지막 활동, 토글, 토큰 카운터 등) 추적</li></ul></li><li><p><strong>트랜스크립트 (<code>&amp;lt;sessionId&amp;gt;.jsonl</code>)</strong></p><ul><li>트리 구조를 가진 추가 전용 트랜스크립트 (항목에는 <code>id</code> + <code>parentId</code>가 있음)</li><li>실제 대화 + 도구 호출 + 컴팩션 요약 저장</li><li>미래 턴의 모델 컨텍스트를 재구성하는 데 사용됨</li></ul></li></ol><hr><h2 id="디스크-위치" tabindex="-1">디스크 위치 <a class="header-anchor" href="#디스크-위치" aria-label="Permalink to &quot;디스크 위치&quot;">​</a></h2><p>게이트웨이 호스트의 에이전트별:</p><ul><li>저장소: <code>~/.openclaw/agents/&amp;lt;agentId&amp;gt;/sessions/sessions.json</code></li><li>트랜스크립트: <code>~/.openclaw/agents/&amp;lt;agentId&amp;gt;/sessions/&amp;lt;sessionId&amp;gt;.jsonl</code><ul><li>Telegram 주제 세션: <code>.../&amp;lt;sessionId&amp;gt;-topic-&amp;lt;threadId&amp;gt;.jsonl</code></li></ul></li></ul><p>OpenClaw는 <code>src/config/sessions.ts</code>를 통해 이를 확인합니다.</p><hr><h2 id="저장소-유지-보수-및-디스크-컨트롤" tabindex="-1">저장소 유지 보수 및 디스크 컨트롤 <a class="header-anchor" href="#저장소-유지-보수-및-디스크-컨트롤" aria-label="Permalink to &quot;저장소 유지 보수 및 디스크 컨트롤&quot;">​</a></h2><p>세션 지속성에는 <code>sessions.json</code> 및 트랜스크립트 아티팩트에 대한 자동 유지 보수 컨트롤 (<code>session.maintenance</code>)이 있습니다:</p><ul><li><code>mode</code>: <code>warn</code> (기본값) 또는 <code>enforce</code></li><li><code>pruneAfter</code>: 오래된 항목 연령 기준 (기본값 <code>30d</code>)</li><li><code>maxEntries</code>: <code>sessions.json</code>의 항목 수 제한 (기본값 <code>500</code>)</li><li><code>rotateBytes</code>: 과도하게 큰 경우 <code>sessions.json</code> 교체 (기본값 <code>10mb</code>)</li><li><code>resetArchiveRetention</code>: <code>*.reset.&amp;lt;timestamp&amp;gt;</code> 트랜스크립트 아카이브 보존 (기본값: <code>pruneAfter</code>와 동일; <code>false</code>는 정리 비활성화)</li><li><code>maxDiskBytes</code>: 선택적 세션 디렉토리 예산</li><li><code>highWaterBytes</code>: 정리 후 선택적 대상 (기본값 <code>maxDiskBytes</code>의 <code>80%</code>)</li></ul><p>디스크 예산 정리 적용 순서 (<code>mode: &quot;enforce&quot;</code>):</p><ol><li>가장 오래된 아카이브 또는 고아 트랜스크립트 아티팩트를 먼저 제거합니다.</li><li>여전히 대상 이상인 경우 가장 오래된 세션 항목과 해당 트랜스크립트 파일을 제거합니다.</li><li>사용량이 <code>highWaterBytes</code> 이하가 될 때까지 계속합니다.</li></ol><p><code>mode: &quot;warn&quot;</code>에서 OpenClaw는 잠재적 제거를 보고하지만 저장소/파일을 변경하지 않습니다.</p><p>요청 시 유지 보수를 실행합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sessions</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cleanup</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sessions</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cleanup</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --enforce</span></span></code></pre></div><hr><h2 id="cron-세션-및-실행-로그" tabindex="-1">Cron 세션 및 실행 로그 <a class="header-anchor" href="#cron-세션-및-실행-로그" aria-label="Permalink to &quot;Cron 세션 및 실행 로그&quot;">​</a></h2><p>격리된 cron 실행도 세션 항목/트랜스크립트를 생성하며 전용 보존 컨트롤이 있습니다:</p><ul><li><code>cron.sessionRetention</code> (기본값 <code>24h</code>)은 세션 저장소에서 이전 격리 cron 실행 세션을 프루닝합니다 (<code>false</code>는 비활성화).</li><li><code>cron.runLog.maxBytes</code> + <code>cron.runLog.keepLines</code>는 <code>~/.openclaw/cron/runs/&amp;lt;jobId&amp;gt;.jsonl</code> 파일을 프루닝합니다 (기본값: <code>2_000_000</code> 바이트 및 <code>2000</code> 줄).</li></ul><hr><h2 id="세션-키-sessionkey" tabindex="-1">세션 키 (<code>sessionKey</code>) <a class="header-anchor" href="#세션-키-sessionkey" aria-label="Permalink to &quot;세션 키 (`sessionKey`)&quot;">​</a></h2><p><code>sessionKey</code>는 <em>어떤 대화 버킷에 있는지</em> 를 식별합니다 (라우팅 + 격리).</p><p>일반적인 패턴:</p><ul><li>메인/다이렉트 채팅 (에이전트별): <code>agent:&amp;lt;agentId&amp;gt;:&amp;lt;mainKey&amp;gt;</code> (기본값 <code>main</code>)</li><li>그룹: <code>agent:&amp;lt;agentId&amp;gt;:&amp;lt;channel&amp;gt;:group:&amp;lt;id&amp;gt;</code></li><li>룸/채널 (Discord/Slack): <code>agent:&amp;lt;agentId&amp;gt;:&amp;lt;channel&amp;gt;:channel:&amp;lt;id&amp;gt;</code> 또는 <code>...:room:&amp;lt;id&amp;gt;</code></li><li>Cron: <code>cron:&amp;lt;job.id&amp;gt;</code></li><li>웹훅: <code>hook:&amp;lt;uuid&amp;gt;</code> (재정의하지 않는 한)</li></ul><p>표준 규칙은 <a href="/openclaw-docs-ko/concepts/session">/concepts/session</a>에 문서화되어 있습니다.</p><hr><h2 id="세션-id-sessionid" tabindex="-1">세션 ID (<code>sessionId</code>) <a class="header-anchor" href="#세션-id-sessionid" aria-label="Permalink to &quot;세션 ID (`sessionId`)&quot;">​</a></h2><p>각 <code>sessionKey</code>는 현재 <code>sessionId</code> (대화를 계속하는 트랜스크립트 파일)를 가리킵니다.</p><p>경험 법칙:</p><ul><li><strong>재설정</strong> (<code>/new</code>, <code>/reset</code>)은 해당 <code>sessionKey</code>에 대한 새 <code>sessionId</code>를 생성합니다.</li><li><strong>일일 재설정</strong> (기본값 게이트웨이 호스트의 로컬 시간 오전 4시)은 재설정 경계 후 다음 메시지에 새 <code>sessionId</code>를 생성합니다.</li><li><strong>유휴 만료</strong> (<code>session.reset.idleMinutes</code> 또는 레거시 <code>session.idleMinutes</code>)는 유휴 창 후 메시지가 도착하면 새 <code>sessionId</code>를 생성합니다. 일일과 유휴가 모두 구성된 경우 먼저 만료되는 것이 우선합니다.</li><li><strong>스레드 부모 포크 가드</strong> (<code>session.parentForkMaxTokens</code>, 기본값 <code>100000</code>)는 부모 세션이 이미 너무 큰 경우 부모 트랜스크립트 포킹을 건너뜁니다. 새 스레드는 새로 시작됩니다. <code>0</code>으로 설정하면 비활성화됩니다.</li></ul><p>구현 세부 사항: 결정은 <code>src/auto-reply/reply/session.ts</code>의 <code>initSessionState()</code>에서 발생합니다.</p><hr><h2 id="세션-저장소-스키마-sessions-json" tabindex="-1">세션 저장소 스키마 (<code>sessions.json</code>) <a class="header-anchor" href="#세션-저장소-스키마-sessions-json" aria-label="Permalink to &quot;세션 저장소 스키마 (`sessions.json`)&quot;">​</a></h2><p>저장소의 값 타입은 <code>src/config/sessions.ts</code>의 <code>SessionEntry</code>입니다.</p><p>주요 필드 (전체 목록 아님):</p><ul><li><code>sessionId</code>: 현재 트랜스크립트 ID (파일 이름은 <code>sessionFile</code>이 설정되지 않는 한 여기서 파생됨)</li><li><code>updatedAt</code>: 마지막 활동 타임스탬프</li><li><code>sessionFile</code>: 선택적 명시적 트랜스크립트 경로 재정의</li><li><code>chatType</code>: <code>direct | group | room</code> (UI 및 전송 정책에 도움이 됨)</li><li><code>provider</code>, <code>subject</code>, <code>room</code>, <code>space</code>, <code>displayName</code>: 그룹/채널 레이블링을 위한 메타데이터</li><li>토글: <ul><li><code>thinkingLevel</code>, <code>verboseLevel</code>, <code>reasoningLevel</code>, <code>elevatedLevel</code></li><li><code>sendPolicy</code> (세션별 재정의)</li></ul></li><li>모델 선택: <ul><li><code>providerOverride</code>, <code>modelOverride</code>, <code>authProfileOverride</code></li></ul></li><li>토큰 카운터 (최선의 노력 / 프로바이더 의존적): <ul><li><code>inputTokens</code>, <code>outputTokens</code>, <code>totalTokens</code>, <code>contextTokens</code></li></ul></li><li><code>compactionCount</code>: 이 세션 키에 대해 자동 컴팩션이 완료된 횟수</li><li><code>memoryFlushAt</code>: 마지막 사전 컴팩션 메모리 플러시의 타임스탬프</li><li><code>memoryFlushCompactionCount</code>: 마지막 플러시가 실행된 시점의 컴팩션 횟수</li></ul><p>저장소는 편집이 안전하지만 게이트웨이가 권한입니다: 세션이 실행될 때 항목을 다시 쓰거나 재수화할 수 있습니다.</p><hr><h2 id="트랜스크립트-구조-jsonl" tabindex="-1">트랜스크립트 구조 (<code>*.jsonl</code>) <a class="header-anchor" href="#트랜스크립트-구조-jsonl" aria-label="Permalink to &quot;트랜스크립트 구조 (`*.jsonl`)&quot;">​</a></h2><p>트랜스크립트는 <code>@mariozechner/pi-coding-agent</code>의 <code>SessionManager</code>에 의해 관리됩니다.</p><p>파일은 JSONL입니다:</p><ul><li>첫 번째 줄: 세션 헤더 (<code>type: &quot;session&quot;</code>, <code>id</code>, <code>cwd</code>, <code>timestamp</code>, 선택적 <code>parentSession</code> 포함)</li><li>그 다음: <code>id</code> + <code>parentId</code>가 있는 세션 항목 (트리)</li></ul><p>주요 항목 타입:</p><ul><li><code>message</code>: 사용자/어시스턴트/도구 결과 메시지</li><li><code>custom_message</code>: 모델 컨텍스트에 <em>들어가는</em> 확장 주입 메시지 (UI에서 숨길 수 있음)</li><li><code>custom</code>: 모델 컨텍스트에 <em>들어가지 않는</em> 확장 상태</li><li><code>compaction</code>: <code>firstKeptEntryId</code> 및 <code>tokensBefore</code>가 있는 지속된 컴팩션 요약</li><li><code>branch_summary</code>: 트리 브랜치 탐색 시 지속된 요약</li></ul><p>OpenClaw는 트랜스크립트를 의도적으로 &quot;수정&quot;하지 않습니다. 게이트웨이는 <code>SessionManager</code>를 사용하여 읽기/쓰기합니다.</p><hr><h2 id="컨텍스트-창-대-추적-토큰" tabindex="-1">컨텍스트 창 대 추적 토큰 <a class="header-anchor" href="#컨텍스트-창-대-추적-토큰" aria-label="Permalink to &quot;컨텍스트 창 대 추적 토큰&quot;">​</a></h2><p>두 가지 다른 개념이 중요합니다:</p><ol><li><strong>모델 컨텍스트 창</strong>: 모델당 하드 상한 (모델에 표시되는 토큰)</li><li><strong>세션 저장소 카운터</strong>: <code>sessions.json</code>에 기록된 롤링 통계 (/status 및 대시보드에 사용됨)</li></ol><p>제한을 조정하는 경우:</p><ul><li>컨텍스트 창은 모델 카탈로그에서 가져옵니다 (구성으로 재정의할 수 있음).</li><li>저장소의 <code>contextTokens</code>는 런타임 추정/보고 값입니다. 엄격한 보장으로 취급하지 마십시오.</li></ul><p>자세한 내용은 <a href="/openclaw-docs-ko/reference/token-use">/token-use</a>를 참조하십시오.</p><hr><h2 id="컴팩션-개념" tabindex="-1">컴팩션: 개념 <a class="header-anchor" href="#컴팩션-개념" aria-label="Permalink to &quot;컴팩션: 개념&quot;">​</a></h2><p>컴팩션은 이전 대화를 트랜스크립트의 지속된 <code>compaction</code> 항목으로 요약하고 최근 메시지는 그대로 유지합니다.</p><p>컴팩션 후 미래 턴은 다음을 보게 됩니다:</p><ul><li>컴팩션 요약</li><li><code>firstKeptEntryId</code> 이후의 메시지</li></ul><p>컴팩션은 <strong>지속적</strong>입니다 (세션 프루닝과 달리). <a href="/openclaw-docs-ko/concepts/session-pruning">/concepts/session-pruning</a>을 참조하십시오.</p><h2 id="컴팩션-청크-경계-및-도구-페어링" tabindex="-1">컴팩션 청크 경계 및 도구 페어링 <a class="header-anchor" href="#컴팩션-청크-경계-및-도구-페어링" aria-label="Permalink to &quot;컴팩션 청크 경계 및 도구 페어링&quot;">​</a></h2><p>OpenClaw가 긴 트랜스크립트를 컴팩션 청크로 분할할 때 어시스턴트 도구 호출을 일치하는 <code>toolResult</code> 항목과 페어링된 상태로 유지합니다.</p><ul><li>토큰 공유 분할이 도구 호출과 결과 사이에 도달하면 OpenClaw는 페어를 분리하는 대신 경계를 어시스턴트 도구 호출 메시지로 이동합니다.</li><li>후행 도구 결과 블록이 청크를 대상 이상으로 밀어붙이는 경우 OpenClaw는 해당 보류 중인 도구 블록을 보존하고 요약되지 않은 꼬리를 그대로 유지합니다.</li><li>중단/오류 도구 호출 블록은 보류 중인 분할을 열어두지 않습니다.</li></ul><hr><h2 id="자동-컴팩션이-발생하는-시점-pi-런타임" tabindex="-1">자동 컴팩션이 발생하는 시점 (Pi 런타임) <a class="header-anchor" href="#자동-컴팩션이-발생하는-시점-pi-런타임" aria-label="Permalink to &quot;자동 컴팩션이 발생하는 시점 (Pi 런타임)&quot;">​</a></h2><p>임베디드 Pi 에이전트에서 자동 컴팩션은 두 가지 경우에 트리거됩니다:</p><ol><li><strong>오버플로우 복구</strong>: 모델이 컨텍스트 오버플로우 오류를 반환함 (<code>request_too_large</code>, <code>context length exceeded</code>, <code>input exceeds the maximum number of tokens</code>, <code>input token count exceeds the maximum number of input tokens</code>, <code>input is too long for the model</code>, <code>ollama error: context length exceeded</code>, 및 유사한 프로바이더 형태 변형) → 컴팩션 → 재시도.</li><li><strong>임계값 유지</strong>: 성공적인 턴 후:</li></ol><p><code>contextTokens &gt; contextWindow - reserveTokens</code></p><p>여기서:</p><ul><li><code>contextWindow</code>는 모델의 컨텍스트 창</li><li><code>reserveTokens</code>는 프롬프트 + 다음 모델 출력을 위해 예약된 여유 공간</li></ul><p>이것은 Pi 런타임 의미론입니다 (OpenClaw는 이벤트를 소비하지만 Pi가 컴팩션 시점을 결정합니다).</p><hr><h2 id="컴팩션-설정-reservetokens-keeprecenttokens" tabindex="-1">컴팩션 설정 (<code>reserveTokens</code>, <code>keepRecentTokens</code>) <a class="header-anchor" href="#컴팩션-설정-reservetokens-keeprecenttokens" aria-label="Permalink to &quot;컴팩션 설정 (`reserveTokens`, `keepRecentTokens`)&quot;">​</a></h2><p>Pi의 컴팩션 설정은 Pi 설정에 있습니다:</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  compaction</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    reserveTokens</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16384</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    keepRecentTokens</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">20000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>OpenClaw는 임베디드 실행에 대한 안전 플로어도 적용합니다:</p><ul><li><code>compaction.reserveTokens &lt; reserveTokensFloor</code>이면 OpenClaw가 올립니다.</li><li>기본 플로어는 <code>20000</code> 토큰입니다.</li><li><code>agents.defaults.compaction.reserveTokensFloor: 0</code>으로 플로어를 비활성화합니다.</li><li>이미 더 높은 경우 OpenClaw는 그대로 둡니다.</li></ul><p>이유: 컴팩션이 불가피해지기 전에 멀티 턴 &quot;하우스키핑&quot; (메모리 쓰기 등)을 위한 충분한 여유 공간을 남겨두기 위해서입니다.</p><p>구현: <code>src/agents/pi-settings.ts</code>의 <code>ensurePiCompactionReserveTokens()</code> (<code>src/agents/pi-embedded-runner.ts</code>에서 호출됨).</p><hr><h2 id="플러그형-컴팩션-프로바이더" tabindex="-1">플러그형 컴팩션 프로바이더 <a class="header-anchor" href="#플러그형-컴팩션-프로바이더" aria-label="Permalink to &quot;플러그형 컴팩션 프로바이더&quot;">​</a></h2><p>플러그인은 플러그인 API의 <code>registerCompactionProvider()</code>를 통해 컴팩션 프로바이더를 등록할 수 있습니다. <code>agents.defaults.compaction.provider</code>가 등록된 프로바이더 ID로 설정된 경우 안전망 확장은 내장된 <code>summarizeInStages</code> 파이프라인 대신 해당 프로바이더에게 요약을 위임합니다.</p><ul><li><code>provider</code>: 등록된 컴팩션 프로바이더 플러그인의 ID. 기본 LLM 요약은 설정하지 않습니다.</li><li><code>provider</code>를 설정하면 <code>mode: &quot;safeguard&quot;</code>가 강제됩니다.</li><li>프로바이더는 내장 경로와 동일한 컴팩션 지침 및 식별자 보존 정책을 받습니다.</li><li>안전망은 프로바이더 출력 후에도 최근 턴 및 분할 턴 접미사 컨텍스트를 보존합니다.</li><li>프로바이더가 실패하거나 빈 결과를 반환하면 OpenClaw는 자동으로 내장 LLM 요약으로 폴백합니다.</li><li>중단/타임아웃 신호는 호출자 취소를 존중하기 위해 삼켜지지 않고 다시 던져집니다.</li></ul><p>소스: <code>src/plugins/compaction-provider.ts</code>, <code>src/agents/pi-hooks/compaction-safeguard.ts</code>.</p><hr><h2 id="사용자-대면-서페이스" tabindex="-1">사용자 대면 서페이스 <a class="header-anchor" href="#사용자-대면-서페이스" aria-label="Permalink to &quot;사용자 대면 서페이스&quot;">​</a></h2><p>다음을 통해 컴팩션 및 세션 상태를 관찰할 수 있습니다:</p><ul><li><code>/status</code> (모든 채팅 세션에서)</li><li><code>openclaw status</code> (CLI)</li><li><code>openclaw sessions</code> / <code>sessions --json</code></li><li>자세한 모드: <code>🧹 자동 컴팩션 완료</code> + 컴팩션 횟수</li></ul><hr><h2 id="사일런트-하우스키핑-no-reply" tabindex="-1">사일런트 하우스키핑 (<code>NO_REPLY</code>) <a class="header-anchor" href="#사일런트-하우스키핑-no-reply" aria-label="Permalink to &quot;사일런트 하우스키핑 (`NO_REPLY`)&quot;">​</a></h2><p>OpenClaw는 사용자가 중간 출력을 보지 않아야 하는 백그라운드 작업을 위한 &quot;사일런트&quot; 턴을 지원합니다.</p><p>관례:</p><ul><li>어시스턴트는 출력을 정확한 사일런트 토큰 <code>NO_REPLY</code> / <code>no_reply</code>로 시작하여 &quot;사용자에게 응답을 전달하지 마십시오&quot;를 나타냅니다.</li><li>OpenClaw는 전달 레이어에서 이를 제거/억제합니다.</li><li>정확한 사일런트 토큰 억제는 대소문자를 구분하지 않습니다. 전체 페이로드가 사일런트 토큰인 경우 <code>NO_REPLY</code>와 <code>no_reply</code> 모두 해당됩니다.</li><li>이것은 진정한 백그라운드/무전달 턴만을 위한 것입니다. 일반적인 실행 가능한 사용자 요청에 대한 단축키가 아닙니다.</li></ul><p><code>2026.1.10</code>부터 OpenClaw는 부분 청크가 <code>NO_REPLY</code>로 시작될 때 <strong>드래프트/타이핑 스트리밍</strong>도 억제합니다. 따라서 사일런트 작업이 턴 중간에 부분 출력을 누설하지 않습니다.</p><hr><h2 id="사전-컴팩션-메모리-플러시-구현됨" tabindex="-1">사전 컴팩션 &quot;메모리 플러시&quot; (구현됨) <a class="header-anchor" href="#사전-컴팩션-메모리-플러시-구현됨" aria-label="Permalink to &quot;사전 컴팩션 &quot;메모리 플러시&quot; (구현됨)&quot;">​</a></h2><p>목표: 자동 컴팩션이 발생하기 전에 사일런트 에이전틱 턴을 실행하여 컴팩션이 중요한 컨텍스트를 지울 수 없도록 내구성 있는 상태를 디스크 (예: 에이전트 워크스페이스의 <code>memory/YYYY-MM-DD.md</code>)에 씁니다.</p><p>OpenClaw는 <strong>사전 임계값 플러시</strong> 접근 방식을 사용합니다:</p><ol><li>세션 컨텍스트 사용량을 모니터링합니다.</li><li>&quot;소프트 임계값&quot; (Pi의 컴팩션 임계값 이하)을 초과하면 에이전트에게 사일런트 &quot;지금 메모리 쓰기&quot; 지시문을 실행합니다.</li><li>사용자가 아무것도 보지 않도록 정확한 사일런트 토큰 <code>NO_REPLY</code> / <code>no_reply</code>를 사용합니다.</li></ol><p>구성 (<code>agents.defaults.compaction.memoryFlush</code>):</p><ul><li><code>enabled</code> (기본값: <code>true</code>)</li><li><code>softThresholdTokens</code> (기본값: <code>4000</code>)</li><li><code>prompt</code> (플러시 턴을 위한 사용자 메시지)</li><li><code>systemPrompt</code> (플러시 턴을 위해 추가되는 추가 시스템 프롬프트)</li></ul><p>메모:</p><ul><li>기본 프롬프트/시스템 프롬프트에는 전달을 억제하기 위한 <code>NO_REPLY</code> 힌트가 포함됩니다.</li><li>플러시는 컴팩션 주기당 한 번 실행됩니다 (<code>sessions.json</code>에서 추적됨).</li><li>플러시는 임베디드 Pi 세션에 대해서만 실행됩니다 (CLI 백엔드는 건너뜁니다).</li><li>세션 워크스페이스가 읽기 전용 (<code>workspaceAccess: &quot;ro&quot;</code> 또는 <code>&quot;none&quot;</code>)인 경우 플러시가 건너뜁니다.</li><li>워크스페이스 파일 레이아웃 및 쓰기 패턴은 <a href="/openclaw-docs-ko/concepts/memory">메모리</a>를 참조하십시오.</li></ul><p>Pi는 확장 API에서 <code>session_before_compact</code> 훅을 노출하지만 OpenClaw의 플러시 로직은 현재 게이트웨이 측에 있습니다.</p><hr><h2 id="문제-해결-체크리스트" tabindex="-1">문제 해결 체크리스트 <a class="header-anchor" href="#문제-해결-체크리스트" aria-label="Permalink to &quot;문제 해결 체크리스트&quot;">​</a></h2><ul><li>세션 키가 잘못되었습니까? <a href="/openclaw-docs-ko/concepts/session">/concepts/session</a>에서 시작하여 <code>/status</code>에서 <code>sessionKey</code>를 확인하십시오.</li><li>저장소 대 트랜스크립트 불일치? <code>openclaw status</code>에서 게이트웨이 호스트 및 저장소 경로를 확인하십시오.</li><li>컴팩션 스팸? 확인: <ul><li>모델 컨텍스트 창 (너무 작음)</li><li>컴팩션 설정 (<code>reserveTokens</code>가 모델 창에 비해 너무 높으면 더 일찍 컴팩션이 발생할 수 있음)</li><li>도구 결과 팽창: 세션 프루닝 활성화/조정</li></ul></li><li>사일런트 턴 누설? 응답이 <code>NO_REPLY</code>로 시작하는지 (대소문자 구분 없이 정확한 토큰) 확인하고 스트리밍 억제 수정이 포함된 빌드에 있는지 확인하십시오.</li></ul>',117)])])}const m=o(l,[["render",a]]);export{u as __pageData,m as default};
